import assert from "node:assert/strict";
import test from "node:test";
import { createWebVitalsTelemetryController } from "../../controllers/web-vitals-telemetry.controller";
import { errorHandler } from "../../middleware/error-handler";
import {
  createWebVitalsTelemetryDropGuard,
  createWebVitalsTelemetryRequestGuard,
  registerTelemetryRoutes,
} from "../telemetry.routes";
import {
  createJsonTestApp,
  startTestServer,
  stopTestServer,
} from "./http-test-utils";

function createTelemetryRouteHarness(options: {
  webVitalsDropGuard?: Parameters<typeof registerTelemetryRoutes>[1]["webVitalsDropGuard"];
  webVitalsRequestGuard?: Parameters<typeof registerTelemetryRoutes>[1]["webVitalsRequestGuard"];
} = {}) {
  const recordedPayloads: Array<Record<string, unknown>> = [];

  const app = createJsonTestApp();
  registerTelemetryRoutes(app, {
    ...(options.webVitalsDropGuard ? { webVitalsDropGuard: options.webVitalsDropGuard } : {}),
    ...(options.webVitalsRequestGuard ? { webVitalsRequestGuard: options.webVitalsRequestGuard } : {}),
    reportWebVital: createWebVitalsTelemetryController({
      webVitalsTelemetryService: {
        record(payload) {
          recordedPayloads.push(payload as Record<string, unknown>);
        },
      },
    }).report,
  });
  app.use(errorHandler);

  return {
    app,
    recordedPayloads,
  };
}

function createValidWebVitalsPayload(overrides: Record<string, unknown> = {}) {
  return {
    name: "LCP",
    value: 2034.781,
    delta: 120.5,
    rating: "good",
    id: "v3-1710000000000-1234567890",
    path: "/login",
    pageType: "public",
    navigationType: "navigate",
    visibilityState: "visible",
    effectiveConnectionType: "4g",
    saveData: false,
    ts: "2026-04-04T08:30:00.000Z",
    ...overrides,
  };
}

test("POST /telemetry/web-vitals accepts a valid web vitals payload", async () => {
  const { app, recordedPayloads } = createTelemetryRouteHarness();
  const { server, baseUrl } = await startTestServer(app);

  try {
    const response = await fetch(`${baseUrl}/telemetry/web-vitals`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(createValidWebVitalsPayload()),
    });

    assert.equal(response.status, 204);
    assert.equal(recordedPayloads.length, 1);
    assert.equal(recordedPayloads[0]?.name, "LCP");
    assert.equal(recordedPayloads[0]?.path, "/login");
  } finally {
    await stopTestServer(server);
  }
});

test("POST /telemetry/web-vitals silently drops excess samples per client window", async () => {
  let nowMs = 1_000;
  const { app, recordedPayloads } = createTelemetryRouteHarness({
    webVitalsDropGuard: createWebVitalsTelemetryDropGuard({
      maxEventsPerWindow: 2,
      now: () => nowMs,
      windowMs: 1_000,
    }),
  });
  const { server, baseUrl } = await startTestServer(app);

  const postMetric = (id: string) => fetch(`${baseUrl}/telemetry/web-vitals`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(createValidWebVitalsPayload({ id })),
  });

  try {
    const first = await postMetric("v3-1710000000000-1");
    const second = await postMetric("v3-1710000000000-2");
    const dropped = await postMetric("v3-1710000000000-3");

    assert.equal(first.status, 204);
    assert.equal(second.status, 204);
    assert.equal(dropped.status, 204);
    assert.equal(recordedPayloads.length, 2);

    nowMs += 1_001;
    const afterWindow = await postMetric("v3-1710000000000-4");
    assert.equal(afterWindow.status, 204);
    assert.equal(recordedPayloads.length, 3);
  } finally {
    await stopTestServer(server);
  }
});

test("POST /telemetry/web-vitals silently drops cross-site browser telemetry attempts", async () => {
  const { app, recordedPayloads } = createTelemetryRouteHarness({
    webVitalsRequestGuard: createWebVitalsTelemetryRequestGuard({
      allowedOrigins: ["https://sqr-system.test"],
    }),
  });
  const { server, baseUrl } = await startTestServer(app);

  try {
    const response = await fetch(`${baseUrl}/telemetry/web-vitals`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Origin: "https://attacker.example",
        "Sec-Fetch-Site": "cross-site",
      },
      body: JSON.stringify(createValidWebVitalsPayload()),
    });

    assert.equal(response.status, 204);
    assert.equal(recordedPayloads.length, 0);
  } finally {
    await stopTestServer(server);
  }
});

test("POST /telemetry/web-vitals silently drops non-json telemetry bodies", async () => {
  const { app, recordedPayloads } = createTelemetryRouteHarness();
  const { server, baseUrl } = await startTestServer(app);

  try {
    const response = await fetch(`${baseUrl}/telemetry/web-vitals`, {
      method: "POST",
      headers: {
        "Content-Type": "text/plain",
      },
      body: JSON.stringify(createValidWebVitalsPayload()),
    });

    assert.equal(response.status, 204);
    assert.equal(recordedPayloads.length, 0);
  } finally {
    await stopTestServer(server);
  }
});

test("POST /telemetry/web-vitals silently drops oversized telemetry bodies before recording", async () => {
  const { app, recordedPayloads } = createTelemetryRouteHarness({
    webVitalsRequestGuard: createWebVitalsTelemetryRequestGuard({
      maxContentLengthBytes: 128,
    }),
  });
  const { server, baseUrl } = await startTestServer(app);

  try {
    const response = await fetch(`${baseUrl}/telemetry/web-vitals`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(createValidWebVitalsPayload({
        id: `v3-${"oversized".repeat(20)}`,
      })),
    });

    assert.equal(response.status, 204);
    assert.equal(recordedPayloads.length, 0);
  } finally {
    await stopTestServer(server);
  }
});

test("POST /telemetry/web-vitals rejects malformed payloads with a validation error", async () => {
  const { app, recordedPayloads } = createTelemetryRouteHarness();
  const { server, baseUrl } = await startTestServer(app);

  try {
    const response = await fetch(`${baseUrl}/telemetry/web-vitals`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        name: "INVALID",
        value: -1,
        delta: 0,
        rating: "good",
        id: "",
        path: "login",
        pageType: "public",
        ts: "",
      }),
    });

    assert.equal(response.status, 400);
    const payload = await response.json();
    assert.equal(payload.error.code, "REQUEST_BODY_INVALID");
    assert.equal(recordedPayloads.length, 0);
  } finally {
    await stopTestServer(server);
  }
});

import type { RequestHandler } from "express";
import { parseRequestBody } from "../http/validation";
import { webVitalTelemetrySchema } from "../../shared/web-vitals";
import type { WebVitalsTelemetryService } from "../services/web-vitals-telemetry.service";

type CreateWebVitalsTelemetryControllerOptions = {
  webVitalsTelemetryService: Pick<WebVitalsTelemetryService, "record">;
};

export function createWebVitalsTelemetryController(
  options: CreateWebVitalsTelemetryControllerOptions,
): { report: RequestHandler } {
  const { webVitalsTelemetryService } = options;

  return {
    report(req, res) {
      const payload = parseRequestBody(webVitalTelemetrySchema, req.body);
      webVitalsTelemetryService.record(payload);
      res.status(204).end();
    },
  };
}

import { z } from "zod";
import { ERROR_CODES } from "../../shared/error-codes";
import { badRequest } from "./errors";

export function ensureObject(value: unknown): Record<string, unknown> | null {
  if (value && typeof value === "object" && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return null;
}

export type RequestValidationIssue = {
  code: string;
  message: string;
  path: string;
};

function buildRequestValidationIssues(error: z.ZodError): RequestValidationIssue[] {
  return error.issues.map((issue) => ({
    code: issue.code,
    message: issue.message,
    path: issue.path.length > 0 ? issue.path.map(String).join(".") : "body",
  }));
}

export function parseRequestBody<TSchema extends z.ZodTypeAny>(
  schema: TSchema,
  value: unknown,
): z.infer<TSchema> {
  const parsed = schema.safeParse(value);
  if (parsed.success) {
    return parsed.data;
  }

  const details = buildRequestValidationIssues(parsed.error);
  throw badRequest(
    details[0]?.message || "Request body is invalid.",
    ERROR_CODES.REQUEST_BODY_INVALID,
    details,
  );
}

export const DEFAULT_READ_STRING_MAX_LENGTH = 2_048;

export function readNonEmptyString(
  value: unknown,
  maxLength = DEFAULT_READ_STRING_MAX_LENGTH,
): string {
  const normalized = String(value ?? "").trim();
  if (normalized.length > maxLength) {
    throw badRequest(
      `String value exceeds maximum length of ${maxLength} characters.`,
      ERROR_CODES.REQUEST_BODY_INVALID,
    );
  }
  return normalized;
}

export function readOptionalString(
  value: unknown,
  maxLength = DEFAULT_READ_STRING_MAX_LENGTH,
): string | undefined {
  const normalized = readNonEmptyString(value, maxLength);
  return normalized || undefined;
}

export function readInteger(value: unknown, fallback: number): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.trunc(parsed);
}

export function clampInteger(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, Math.trunc(value)));
}

const TRUTHY_BOOLEAN_LITERALS = new Set(["1", "true", "yes", "on"]);
const FALSY_BOOLEAN_LITERALS = new Set(["0", "false", "no", "off"]);

export function readBooleanFlag(value: unknown): boolean {
  if (typeof value === "boolean") return value;
  const normalized = readNonEmptyString(value).toLowerCase();
  if (!normalized) {
    return false;
  }

  if (TRUTHY_BOOLEAN_LITERALS.has(normalized)) {
    return true;
  }

  if (FALSY_BOOLEAN_LITERALS.has(normalized)) {
    return false;
  }

  throw badRequest(
    "Boolean flag must be one of: true, false, 1, 0, yes, no, on, off.",
    ERROR_CODES.REQUEST_BODY_INVALID,
  );
}

function parseEscapedStringList(value: string): string[] {
  const values: string[] = [];
  let current = "";
  let escaping = false;

  for (const character of value) {
    if (escaping) {
      current += character;
      escaping = false;
      continue;
    }

    if (character === "\\") {
      escaping = true;
      continue;
    }

    if (character === ",") {
      values.push(current);
      current = "";
      continue;
    }

    current += character;
  }

  if (escaping) {
    current += "\\";
  }

  values.push(current);
  return values;
}

export function readStringList(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value
      .map((item) => readNonEmptyString(item))
      .filter(Boolean);
  }

  const normalized = readNonEmptyString(value);
  if (!normalized) return [];

  return parseEscapedStringList(normalized)
    .map((part) => readNonEmptyString(part))
    .filter(Boolean);
}

export function readDate(value: unknown): Date | undefined {
  const normalized = readNonEmptyString(value);
  if (!normalized) return undefined;

  const parsed = new Date(normalized);
  if (Number.isNaN(parsed.getTime())) {
    return undefined;
  }

  return parsed;
}

export class HttpError extends Error {
  readonly statusCode: number;
  readonly code?: string | undefined;
  readonly details?: unknown;
  readonly expose: boolean;

  constructor(
    statusCode: number,
    message: string,
    options?: { code?: string | undefined; details?: unknown; expose?: boolean | undefined },
  ) {
    super(message);
    this.name = "HttpError";
    this.statusCode = statusCode;
    this.code = options?.code;
    this.details = options?.details;
    this.expose = options?.expose ?? statusCode < 500;
  }
}

export function badRequest(message: string, code?: string, details?: unknown) {
  return new HttpError(400, message, { code, details });
}

export function unauthorized(message = "Authentication required.", code?: string) {
  return new HttpError(401, message, { code });
}

export function forbidden(message = "Insufficient permissions.", code?: string) {
  return new HttpError(403, message, { code });
}

export function notFound(message = "Resource not found.", code?: string) {
  return new HttpError(404, message, { code });
}

export function conflict(message: string, code?: string) {
  return new HttpError(409, message, { code });
}

import { z } from "zod";

export const WEB_VITAL_NAMES = ["CLS", "FCP", "INP", "LCP", "TTFB"] as const;
export const WEB_VITAL_RATINGS = ["good", "needs-improvement", "poor"] as const;
export const WEB_VITAL_PAGE_TYPES = ["public", "authenticated"] as const;

export const webVitalTelemetrySchema = z.object({
  name: z.enum(WEB_VITAL_NAMES),
  value: z.number().finite().min(0).max(120_000),
  delta: z.number().finite().min(0).max(120_000),
  rating: z.enum(WEB_VITAL_RATINGS),
  id: z.string().trim().min(1).max(160),
  path: z.string().trim().min(1).max(512).regex(/^\//, "Path must start with '/'."),
  pageType: z.enum(WEB_VITAL_PAGE_TYPES),
  navigationType: z.string().trim().min(1).max(64).optional(),
  visibilityState: z.string().trim().min(1).max(32).optional(),
  effectiveConnectionType: z.string().trim().min(1).max(32).optional(),
  saveData: z.boolean().optional(),
  ts: z.string().trim().min(1).max(64),
}).strict();

export const webVitalMetricSummarySchema = z.object({
  name: z.enum(WEB_VITAL_NAMES),
  sampleCount: z.number().int().min(0),
  p75: z.number().finite().min(0).nullable(),
  p75Rating: z.enum(WEB_VITAL_RATINGS).nullable(),
  latestValue: z.number().finite().min(0).nullable(),
  latestRating: z.enum(WEB_VITAL_RATINGS).nullable(),
  latestCapturedAt: z.string().trim().min(1).max(64).nullable(),
  latestPath: z.string().trim().min(1).max(512).nullable(),
});

export const webVitalPageSummarySchema = z.object({
  pageType: z.enum(WEB_VITAL_PAGE_TYPES),
  sampleCount: z.number().int().min(0),
  latestCapturedAt: z.string().trim().min(1).max(64).nullable(),
  metrics: z.array(webVitalMetricSummarySchema),
});

export const webVitalOverviewSchema = z.object({
  windowMinutes: z.number().int().positive(),
  totalSamples: z.number().int().min(0),
  pageSummaries: z.array(webVitalPageSummarySchema),
  updatedAt: z.string().trim().min(1).max(64),
});

export type WebVitalTelemetryPayload = z.infer<typeof webVitalTelemetrySchema>;
export type WebVitalMetricSummary = z.infer<typeof webVitalMetricSummarySchema>;
export type WebVitalPageSummary = z.infer<typeof webVitalPageSummarySchema>;
export type WebVitalOverviewPayload = z.infer<typeof webVitalOverviewSchema>;

import type { NextFunction, Request, Response } from "express";
import { ERROR_CODES } from "../../shared/error-codes";
import { HttpError } from "../http/errors";
import { sanitizeRequestId } from "../http/request-id";
import { wasRouteErrorLogged } from "../http/route-observability";
import { logger } from "../lib/logger";

type ErrorLike = {
  message?: string;
  code?: string;
  type?: string;
  status?: number;
  statusCode?: number;
};

type ApiErrorResponse = {
  ok: false;
  message: string;
  requestId?: string;
  error?: {
    code?: string;
    message: string;
    details?: unknown;
  };
};

function readCorrelationRequestId(req: Request, res: Response): string | undefined {
  const responseRequestId = typeof res.getHeader === "function"
    ? sanitizeRequestId(res.getHeader("x-request-id"))
    : "";
  if (responseRequestId) {
    return responseRequestId;
  }

  const requestHeader = req.headers ? sanitizeRequestId(req.headers["x-request-id"]) : "";
  return requestHeader || undefined;
}

function buildApiErrorResponse(
  message: string,
  options?: {
    code?: string | undefined;
    details?: unknown;
    includeError?: boolean | undefined;
    requestId?: string | undefined;
  },
): ApiErrorResponse {
  const includeError = options?.includeError || Boolean(options?.code || options?.details !== undefined);

  return {
    ok: false,
    message,
    ...(options?.requestId ? { requestId: options.requestId } : {}),
    ...(includeError
      ? {
          error: {
            ...(options?.code ? { code: options.code } : {}),
            message,
            ...(options?.details !== undefined ? { details: options.details } : {}),
          },
        }
      : {}),
  };
}

export function errorHandler(err: unknown, req: Request, res: Response, next: NextFunction) {
  if (res.headersSent) {
    return next(err);
  }

  const error = err as ErrorLike;
  const requestId = readCorrelationRequestId(req, res);

  if (error?.type === "entity.too.large" || error?.status === 413 || error?.statusCode === 413) {
    return res.status(413).json(buildApiErrorResponse("The request payload is too large to process.", {
      code: ERROR_CODES.PAYLOAD_TOO_LARGE,
      includeError: true,
      requestId,
    }));
  }

  if (err instanceof HttpError) {
    if (!err.expose) {
      if (!wasRouteErrorLogged(err)) {
        logger.error("Unhandled API HttpError", {
          path: req.path,
          method: req.method,
          requestId,
          code: err.code,
          statusCode: err.statusCode,
          message: err.message,
        });
      }

      return res.status(err.statusCode).json(buildApiErrorResponse("Internal server error", {
        requestId,
      }));
    }

    return res.status(err.statusCode).json(buildApiErrorResponse(err.message, {
      requestId,
      ...(err.code ? { code: err.code } : {}),
      ...(err.details !== undefined ? { details: err.details } : {}),
    }));
  }

  if (!wasRouteErrorLogged(err)) {
    logger.error("Unhandled API error", {
      path: req.path,
      method: req.method,
      requestId,
      code: error?.code,
      message: error?.message,
    });
  }

  return res.status(500).json(buildApiErrorResponse("Internal server error", {
    requestId,
  }));
}

import { randomUUID } from "node:crypto";

const REQUEST_ID_MAX_LENGTH = 128;
const REQUEST_ID_SAFE_CHAR_PATTERN = /[A-Za-z0-9._:-]/g;

export function sanitizeRequestId(rawRequestId: unknown): string {
  const raw = String(rawRequestId || "").trim();
  if (!raw) {
    return "";
  }

  const safeCharacters = raw.match(REQUEST_ID_SAFE_CHAR_PATTERN)?.join("") || "";
  return safeCharacters.slice(0, REQUEST_ID_MAX_LENGTH);
}

export function resolveRequestId(rawRequestId: unknown): string {
  return sanitizeRequestId(rawRequestId) || randomUUID();
}

import type { NextFunction, Request, RequestHandler, Response } from "express";
import { logger } from "../lib/logger";

const ROUTE_ERROR_LOGGED_SYMBOL = Symbol.for("sqr.routeErrorLogged");

type RouteHandler = (
  req: Request,
  res: Response,
  next: NextFunction,
) => unknown | Promise<unknown>;

type RouteErrorLike = Error & {
  [ROUTE_ERROR_LOGGED_SYMBOL]?: true;
};

type RouteLoggerOptions = {
  message?: string | undefined;
};

function readRoutePath(req: Request) {
  const routePath = req.route?.path;
  return typeof routePath === "string"
    ? routePath
    : Array.isArray(routePath)
      ? routePath.join(",")
      : undefined;
}

export function markRouteErrorLogged(error: unknown) {
  if (!error || typeof error !== "object") {
    return;
  }

  Object.defineProperty(error, ROUTE_ERROR_LOGGED_SYMBOL, {
    configurable: true,
    enumerable: false,
    value: true,
    writable: true,
  });
}

export function wasRouteErrorLogged(error: unknown): boolean {
  return Boolean(
    error &&
    typeof error === "object" &&
    (error as RouteErrorLike)[ROUTE_ERROR_LOGGED_SYMBOL] === true,
  );
}

export function logRouteHandlerError(
  error: unknown,
  req: Request,
  options?: RouteLoggerOptions,
) {
  if (wasRouteErrorLogged(error)) {
    return;
  }

  logger.error(options?.message || "Unhandled route handler error", {
    error,
    method: req.method,
    path: req.path,
    originalUrl: req.originalUrl,
    baseUrl: req.baseUrl || undefined,
    routePath: readRoutePath(req),
    username: (req as { user?: { username?: string | undefined } }).user?.username || undefined,
  });

  markRouteErrorLogged(error);
}

export function routeHandler(
  handler: RouteHandler,
  options?: RouteLoggerOptions,
): RequestHandler {
  return (req, res, next) => {
    void Promise.resolve(handler(req, res, next)).catch((error) => {
      logRouteHandlerError(error, req, options);
      next(error);
    });
  };
}

import pino from "pino";
import { runtimeConfig } from "../config/runtime";
import { getRequestContext } from "./request-context";

const REDACT_KEYS = [
  "password",
  "passwordhash",
  "token",
  "authorization",
  "sessionsecret",
  "icnumber",
  "accountnumber",
  "fingerprint",
  "email",
  "fullname",
  "phone",
  "phonenumber",
  "contactnumber",
  "mobilenumber",
  "customerphone",
  "customername",
  "staffname",
  "amount",
  "customernamesearchhash",
  "icnumbersearchhash",
  "customerphonesearchhash",
  "accountnumbersearchhash",
  "creditcard",
  "bankaccount",
  "secretkey",
  "apikey",
  "accesstoken",
  "refreshtoken",
];

function normalizeSensitiveLogKey(key: string): string {
  return key.toLowerCase().replace(/[^a-z0-9]/g, "");
}

function isSensitiveLogKey(key: string): boolean {
  const normalizedKey = normalizeSensitiveLogKey(key);
  return REDACT_KEYS.some((sensitive) => normalizedKey.includes(sensitive));
}

const EMAIL_CANDIDATE_PATTERN = /\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi;
const PHONE_CANDIDATE_PATTERN = /(?<!\d)(?:\+?60|0)(?:1(?:[ -]?\d){8,9}|[3-9](?:[ -]?\d){7,8})(?!\d)/g;
const CREDIT_CARD_CANDIDATE_PATTERN = /\b(?:\d[ -]?){13,19}\b/g;

function passesLuhnCheck(rawDigits: string): boolean {
  let sum = 0;
  let shouldDouble = false;

  for (let index = rawDigits.length - 1; index >= 0; index -= 1) {
    const digit = Number(rawDigits[index]);
    if (!Number.isInteger(digit)) {
      return false;
    }

    let value = digit;
    if (shouldDouble) {
      value *= 2;
      if (value > 9) {
        value -= 9;
      }
    }

    sum += value;
    shouldDouble = !shouldDouble;
  }

  return rawDigits.length >= 13 && rawDigits.length <= 19 && sum % 10 === 0;
}

function sanitizeLogString(value: string): string {
  const withEmailAddressesRedacted = value.replace(EMAIL_CANDIDATE_PATTERN, "[REDACTED]");
  const withPhoneNumbersRedacted = withEmailAddressesRedacted.replace(PHONE_CANDIDATE_PATTERN, "[REDACTED]");

  return withPhoneNumbersRedacted.replace(CREDIT_CARD_CANDIDATE_PATTERN, (candidate) => {
    const trailingSeparator = candidate.match(/[ -]+$/)?.[0] ?? "";
    const normalizedCandidate = trailingSeparator
      ? candidate.slice(0, -trailingSeparator.length)
      : candidate;
    const digits = normalizedCandidate.replace(/\D/g, "");
    return passesLuhnCheck(digits) ? `[REDACTED]${trailingSeparator}` : candidate;
  });
}

export function sanitizeForLog(value: unknown): unknown {
  if (value instanceof Error) {
    return sanitizeForLog({
      name: value.name,
      message: value.message,
      stack: value.stack,
    });
  }

  if (value instanceof Date) {
    return value.toISOString();
  }

  if (typeof value === "string") {
    return sanitizeLogString(value);
  }

  if (Array.isArray(value)) {
    return value.map((item) => sanitizeForLog(item));
  }

  if (!value || typeof value !== "object") {
    return value;
  }

  const output: Record<string, unknown> = {};
  for (const [key, nested] of Object.entries(value as Record<string, unknown>)) {
    if (isSensitiveLogKey(key)) {
      output[key] = "[REDACTED]";
      continue;
    }
    output[key] = sanitizeForLog(nested);
  }
  return output;
}

const rootLogger = pino({
  level: runtimeConfig.app.logLevel,
  base: null,
  timestamp: pino.stdTimeFunctions.isoTime,
  formatters: {
    level(label) {
      return { level: label };
    },
  },
});

type LogLevel = "info" | "warn" | "error" | "debug";

function write(level: LogLevel, message: string, meta?: Record<string, unknown>) {
  const requestContext = getRequestContext();
  const payload = meta ? sanitizeForLog(meta) : undefined;
  const hasPayload =
    payload &&
    typeof payload === "object" &&
    !Array.isArray(payload) &&
    Object.keys(payload as Record<string, unknown>).length > 0;
  const contextPayload = requestContext
    ? sanitizeForLog({
      requestId: requestContext.requestId,
      ...(requestContext.httpMethod ? { httpMethod: requestContext.httpMethod } : {}),
      ...(requestContext.httpPath ? { httpPath: requestContext.httpPath } : {}),
      ...(requestContext.clientIp ? { clientIp: requestContext.clientIp } : {}),
      ...(requestContext.userAgent ? { userAgent: requestContext.userAgent } : {}),
    }) as Record<string, unknown>
    : null;
  const hasContextPayload = contextPayload && Object.keys(contextPayload).length > 0;

  if (hasPayload || hasContextPayload) {
    rootLogger[level]({
      ...(contextPayload || {}),
      ...((payload as Record<string, unknown>) || {}),
    }, message);
    return;
  }

  rootLogger[level](message);
}

export const logger = {
  info(message: string, meta?: Record<string, unknown>) {
    write("info", message, meta);
  },
  warn(message: string, meta?: Record<string, unknown>) {
    write("warn", message, meta);
  },
  error(message: string, meta?: Record<string, unknown>) {
    write("error", message, meta);
  },
  debug(message: string, meta?: Record<string, unknown>) {
    write("debug", message, meta);
  },
};

