type RuntimeEnvironmentWithOther = "development" | "test" | "production" | "other";

export type RuntimeEnvironment = "development" | "test" | "production";

const TRUE_VALUES = new Set(["1", "true", "yes", "on"]);
const FALSE_VALUES = new Set(["0", "false", "no", "off"]);

type RuntimeEnvironmentSource = Record<string, string | undefined>;

function readOptionalString(name: string, env: RuntimeEnvironmentSource): string | null {
  const value = env[name];
  if (typeof value !== "string") {
    return null;
  }
  const normalized = value.trim();
  return normalized ? normalized : null;
}

export function readBooleanEnvFlag(
  name: string,
  fallback: boolean,
  env: RuntimeEnvironmentSource = process.env,
): boolean {
  const raw = String(readOptionalString(name, env) ?? "").trim().toLowerCase();
  if (!raw) return fallback;
  if (TRUE_VALUES.has(raw)) return true;
  if (FALSE_VALUES.has(raw)) return false;
  return fallback;
}

export function normalizeRuntimeEnvironment(rawValue: unknown): RuntimeEnvironmentWithOther {
  const raw = String(rawValue || "development").trim().toLowerCase();
  if (raw === "development" || raw === "test" || raw === "production") {
    return raw;
  }
  return "other";
}

export function resolveRuntimeEnvironment(rawValue: unknown): RuntimeEnvironment {
  const normalized = normalizeRuntimeEnvironment(rawValue);
  if (normalized === "production" || normalized === "test") {
    return normalized;
  }
  return "development";
}

export function isLoopbackHostname(value: string): boolean {
  const normalized = String(value || "").trim().toLowerCase();
  return normalized === "127.0.0.1" || normalized === "localhost" || normalized === "::1";
}

function resolvePublicAppHost(env: RuntimeEnvironmentSource): string | null {
  const publicBaseUrl =
    readOptionalString("PUBLIC_APP_URL", env)
    || readOptionalString("APP_BASE_URL", env)
    || readOptionalString("CLIENT_APP_URL", env);
  if (!publicBaseUrl) {
    return null;
  }

  try {
    return new URL(publicBaseUrl).hostname || null;
  } catch {
    return null;
  }
}

export function isStrictLocalDevelopmentEnvironment(
  env: RuntimeEnvironmentSource = process.env,
): boolean {
  if (normalizeRuntimeEnvironment(env.NODE_ENV) !== "development") {
    return false;
  }

  const host = readOptionalString("HOST", env);
  if (host && !isLoopbackHostname(host)) {
    return false;
  }

  const publicAppHost = resolvePublicAppHost(env);
  if (!publicAppHost) {
    return true;
  }
  return isLoopbackHostname(publicAppHost);
}

export function isProductionLikeEnvironment(
  env: RuntimeEnvironmentSource = process.env,
): boolean {
  const nodeEnv = normalizeRuntimeEnvironment(env.NODE_ENV);
  if (nodeEnv === "test") {
    return false;
  }
  if (nodeEnv === "production" || nodeEnv === "other") {
    return true;
  }
  return !isStrictLocalDevelopmentEnvironment(env);
}

import { z } from "zod";

type RuntimeEnvironmentSource = Record<string, string | undefined>;

const DEFAULT_STRING_MAX_LENGTH = 4_096;
const SECRET_STRING_MAX_LENGTH = 8_192;
const BOOLEAN_ENV_VALUES = new Set(["1", "0", "true", "false", "yes", "no", "on", "off"]);
const AUTH_COOKIE_SECURE_VALUES = new Set(["auto", "true", "false", "1", "0"]);
const COLLECTION_PII_FIELD_VALUES = new Set([
  "customerName",
  "icNumber",
  "customerPhone",
  "accountNumber",
]);

function normalizeOptionalEnvString(value: unknown) {
  if (value == null) {
    return undefined;
  }
  if (typeof value !== "string") {
    return value;
  }

  const normalized = value.trim();
  return normalized ? normalized : undefined;
}

function optionalEnvString(name: string, maxLength = DEFAULT_STRING_MAX_LENGTH) {
  return z.preprocess(
    normalizeOptionalEnvString,
    z
      .string({ invalid_type_error: `${name} must be a string.` })
      .max(maxLength, `${name} must be ${maxLength} characters or fewer.`)
      .optional(),
  );
}

function optionalBooleanEnv(name: string) {
  return z.preprocess(
    normalizeOptionalEnvString,
    z
      .string({ invalid_type_error: `${name} must be a boolean flag.` })
      .transform((value) => value.toLowerCase())
      .refine(
        (value) => BOOLEAN_ENV_VALUES.has(value),
        `${name} must be a boolean flag (1/0, true/false, yes/no, on/off).`,
      )
      .optional(),
  );
}

function optionalAuthCookieSecureEnv() {
  return z.preprocess(
    normalizeOptionalEnvString,
    z
      .string({ invalid_type_error: "AUTH_COOKIE_SECURE must be a string." })
      .transform((value) => value.toLowerCase())
      .refine(
        (value) => AUTH_COOKIE_SECURE_VALUES.has(value),
        "AUTH_COOKIE_SECURE must be one of: auto, true, false, 1, or 0.",
      )
      .optional(),
  );
}

function optionalIntEnv(name: string, options: { min?: number; max?: number } = {}) {
  return z.preprocess(
    normalizeOptionalEnvString,
    z
      .string({ invalid_type_error: `${name} must be an integer.` })
      .regex(/^-?\d+$/, `${name} must be an integer.`)
      .transform((value) => Number.parseInt(value, 10))
      .refine(
        (value) => Number.isSafeInteger(value),
        `${name} must be a safe integer.`,
      )
      .refine(
        (value) => options.min == null || value >= options.min,
        `${name} must be at least ${options.min}.`,
      )
      .refine(
        (value) => options.max == null || value <= options.max,
        `${name} must be at most ${options.max}.`,
      )
      .optional(),
  );
}

function optionalCollectionPiiRetiredFieldsEnv(name: string) {
  return z.preprocess(
    normalizeOptionalEnvString,
    z
      .string({ invalid_type_error: `${name} must be a comma-separated string.` })
      .refine((value) => {
        const fields = value
          .split(",")
          .map((entry) => entry.trim())
          .filter(Boolean);
        return fields.every((field) => COLLECTION_PII_FIELD_VALUES.has(field));
      }, `${name} must contain only: customerName, icNumber, customerPhone, accountNumber.`)
      .optional(),
  );
}

const runtimeEnvironmentSchema = z.object({
