import type { RequestHandler } from "express";
import { runtimeConfig } from "../config/runtime";
import { logger } from "../lib/logger";

const DEFAULT_ALLOWED_METHODS = "GET, POST, PUT, PATCH, DELETE, OPTIONS";
const DEFAULT_ALLOWED_HEADERS = "Origin, X-Requested-With, Content-Type, Accept, Authorization, X-CSRF-Token, X-Request-Id";
const DEFAULT_PREFLIGHT_MAX_AGE_SECONDS = "600";
const LOCAL_DEV_ORIGINS = [
  "http://localhost:5000",
  "http://127.0.0.1:5000",
  "http://localhost:5173",
  "http://127.0.0.1:5173",
];

type CorsErrorPayload = {
  ok: false;
  error: {
    code: "CORS_ORIGIN_DENIED";
    message: string;
  };
};

type CorsEnvironment = {
  NODE_ENV?: string;
  ALLOW_LOCAL_DEV_CORS?: string;
  PUBLIC_APP_URL?: string;
  CORS_ALLOWED_ORIGINS?: string;
};

type CorsEnvironmentSource = CorsEnvironment | NodeJS.ProcessEnv;

type NormalizeCorsOriginOptions = {
  logInvalid?: boolean;
  source?: string;
};

export function normalizeCorsOrigin(
  value: string | null | undefined,
  options?: NormalizeCorsOriginOptions,
): string | null {
  if (!value) {
    return null;
  }

  const normalizedValue = value.trim();
  if (!normalizedValue) {
    return null;
  }

  try {
    const normalized = new URL(normalizedValue).origin;
    return normalized || null;
  } catch (error) {
    if (options?.logInvalid) {
      logger.warn("Ignoring invalid configured CORS origin", {
        source: options.source ?? "unknown",
        origin: normalizedValue,
        error: error instanceof Error ? error.message : "Invalid URL",
      });
    }
    return null;
  }
}

function buildDefaultCorsEnvironment(): CorsEnvironmentSource {
  return {
    NODE_ENV: runtimeConfig.app.nodeEnv,
    ALLOW_LOCAL_DEV_CORS: runtimeConfig.app.allowLocalDevCors ? "1" : "0",
    PUBLIC_APP_URL: runtimeConfig.app.publicAppUrl ?? undefined,
    CORS_ALLOWED_ORIGINS: runtimeConfig.app.corsAllowedOrigins.join(","),
  };
}

export function resolveAllowedCorsOrigins(env: CorsEnvironmentSource = buildDefaultCorsEnvironment()): string[] {
  const origins = new Set<string>();
  const addOrigin = (value: string | null | undefined, source: string) => {
    const normalized = normalizeCorsOrigin(value, {
      logInvalid: true,
      source,
    });
    if (normalized) {
      origins.add(normalized);
    }
  };

  const configuredOrigins = String(env.CORS_ALLOWED_ORIGINS || "")
    .split(",")
    .map((entry) => entry.trim())
    .filter(Boolean);

  for (const origin of configuredOrigins) {
    addOrigin(origin, "CORS_ALLOWED_ORIGINS");
  }

  addOrigin(env.PUBLIC_APP_URL, "PUBLIC_APP_URL");

  if (
    String(env.NODE_ENV || "development") !== "production"
    && String(env.ALLOW_LOCAL_DEV_CORS || "").trim() === "1"
  ) {
    for (const origin of LOCAL_DEV_ORIGINS) {
      addOrigin(origin, "LOCAL_DEV_ORIGINS");
    }
  }

  return Array.from(origins);
}

export function createCorsMiddleware(
  allowedOrigins = resolveAllowedCorsOrigins(),
): RequestHandler {
  const allowedOriginSet = new Set(
    allowedOrigins
      .map((origin) => normalizeCorsOrigin(origin))
      .filter((origin): origin is string => Boolean(origin)),
  );

  const deniedPayload: CorsErrorPayload = {
    ok: false,
    error: {
      code: "CORS_ORIGIN_DENIED",
      message: "Origin is not allowed.",
    },
  };

  return (req, res, next) => {
    const requestOrigin = normalizeCorsOrigin(req.headers.origin);

    res.header("Vary", "Origin");
    res.header("Access-Control-Allow-Methods", DEFAULT_ALLOWED_METHODS);
    res.header("Access-Control-Allow-Headers", DEFAULT_ALLOWED_HEADERS);

    if (!requestOrigin) {
      if (req.method === "OPTIONS") {
        return res.sendStatus(204);
      }
      return next();
    }

    if (allowedOriginSet.has(requestOrigin)) {
      res.header("Access-Control-Allow-Origin", requestOrigin);
      res.header("Access-Control-Allow-Credentials", "true");
      res.header("Access-Control-Max-Age", DEFAULT_PREFLIGHT_MAX_AGE_SECONDS);
      if (req.method === "OPTIONS") {
        return res.sendStatus(204);
      }
      return next();
    }

    if (req.method === "OPTIONS") {
      return res.status(403).json(deniedPayload);
    }

    return res.status(403).json(deniedPayload);
  };
}

import { once } from "node:events";
import type { Server } from "node:http";
import { AddressInfo } from "node:net";
import express, { type Express, type RequestHandler } from "express";
import type { AuthenticatedRequest, AuthenticatedUser } from "../../auth/guards";

export function createJsonTestApp(): Express {
  const app = express();
  app.use(express.json());
  return app;
}

export async function startTestServer(app: Express) {
  const server = app.listen(0);
  await once(server, "listening");
  const address = server.address() as AddressInfo | null;
  if (!address) {
    throw new Error("Test server failed to start.");
  }

  return {
    server,
    baseUrl: `http://127.0.0.1:${address.port}`,
  };
}

export async function stopTestServer(server: Server) {
  await new Promise<void>((resolve, reject) => {
    server.close((error) => {
      if (error) {
        reject(error);
        return;
      }
      resolve();
    });
  });
}

export function createTestAuthenticateToken(
  defaults?: Partial<AuthenticatedUser>,
): RequestHandler {
  return (req: AuthenticatedRequest, res, next) => {
    const username = String(req.headers["x-test-username"] || defaults?.username || "").trim();
    const role = String(req.headers["x-test-role"] || defaults?.role || "").trim();

    if (!username || !role) {
      res.status(401).json({ message: "Token required" });
      return;
    }

    req.user = {
      userId: String(req.headers["x-test-userid"] || defaults?.userId || "").trim() || undefined,
      username,
      role,
      activityId: String(req.headers["x-test-activityid"] || defaults?.activityId || "test-activity"),
      status: defaults?.status,
      mustChangePassword: defaults?.mustChangePassword,
      passwordResetBySuperuser: defaults?.passwordResetBySuperuser,
      isBanned: defaults?.isBanned ?? null,
    };
    next();
  };
}

export function createTestRequireRole(): (...roles: string[]) => RequestHandler {
  return (...roles: string[]) => (req: AuthenticatedRequest, res, next) => {
    if (!req.user) {
      res.status(401).json({ message: "Authentication required." });
      return;
    }

    if (!roles.includes(req.user.role)) {
      res.status(403).json({ message: "Forbidden" });
      return;
    }

    next();
  };
}

export function createTestRequireTabAccess(): (tabId: string) => RequestHandler {
  return (tabId: string) => (req: AuthenticatedRequest, res, next) => {
    if (!req.user) {
      res.status(401).json({ message: "Unauthenticated" });
      return;
    }

    if (req.user.role === "superuser") {
      next();
      return;
    }

    const deniedTabs = String(req.headers["x-test-deny-tabs"] || "")
      .split(",")
      .map((value) => value.trim())
      .filter(Boolean);

    if (deniedTabs.includes(tabId)) {
      res.status(403).json({ message: `Tab '${tabId}' is disabled for role '${req.user.role}'` });
      return;
    }

    next();
  };
}

export function allowAllTabs(): RequestHandler {
  return (_req, _res, next) => next();
}
